example_bad:
fn compute() -> usize { 42 }

const SIZE: usize = compute(); // Error: not a const fn

fn main() {
    let arr = [0; compute()]; // Error: not a const fn
}

fixes.code:
const fn compute() -> usize { 42 }

const SIZE: usize = compute(); // Works!
let arr = [0; compute()]; // Works!

fn compute() -> usize { 42 }

fn main() {
    let size = compute();
    let v = vec![0; size]; // Vec works with runtime sizes
}
